class Signal:
    def __init__(self):
        self._score = 0.0

    @property
    def score(self):
        return self._score

    @score.setter
    def score(self, v):
        if not 0 <= v <= 1:
            raise ValueError('score fuera de [0,1]')
        self._score = v

s = Signal()
s.score = 0.5
print('ok', s.score)
try:
    s.score = 2
except ValueError as e:
    print('rejected', e)

